+        }
+        return static_cast<T>((static_cast<int64_t>(num1) + static_cast<int64_t>(num2) - 1) /
+            static_cast<int64_t>(num2));
+    }
+    template<typename T>
+    static auto Align(T num1, T num2) -> T
+    {
+        return CeilDivision(num1, num2) * num2;
+    }
