+template <typename T1, typename T2>
+static T1 CeilDiv(T1 a, T2 b)
+{
+    if (b == 0) {
+        return 0;
+    }
+    return (a + b - 1) / b;
+}
+
+template <typename T>
+typename std::enable_if <std::is_integral<T>::value, T>::type CeilAlign(T x, T align) {
+    return CeilDiv(x, align) * align;
+}
