+
+#ifndef __RECURRENT_GATED_DELTA_RULE_KERNEL_H_
+#define __RECURRENT_GATED_DELTA_RULE_KERNEL_H_
+
+#include "kernel_operator.h"
+#include "lib/matmul_intf.h"
